"use client";

import { useEffect, useRef } from "react";

export default function WinLossVoice({
  result,
  payout,
  betAmount,
}: {
  result: "win" | "loss" | null;
  payout?: number;
  betAmount?: number;
}) {
  const hasPlayed = useRef(false);

  useEffect(() => {
    if (!result || hasPlayed.current) return;

    if ("speechSynthesis" in window) {
      let message = "";
      
      if (result === "win") {
        if (payout && betAmount) {
          message = `You win! You won ₹${payout} on your bet of ₹${betAmount}`;
        } else if (payout) {
          message = `You win! You won ₹${payout}`;
        } else {
          message = "You win!";
        }
      } else if (result === "loss") {
        if (betAmount) {
          message = `You loss! You lost ₹${betAmount}`;
        } else {
          message = "You loss!";
        }
      }
      
      const msg = new SpeechSynthesisUtterance(message);

      msg.lang = "en-IN"; // sounds good for Indian accent
      msg.rate = 1;
      msg.pitch = 1;
      msg.volume = 1;

      window.speechSynthesis.cancel(); // stop any previous speech
      window.speechSynthesis.speak(msg);

      hasPlayed.current = true; // prevent replay
    }
  }, [result, payout, betAmount]);

  return null;
}
